#!/usr/bin/perl
use strict;
use warnings;

my %plugins;

sub load_plugins {
    opendir(my $dir, '.') or die "$!";
    my @files = grep { /\.cfg$/ } readdir($dir);

    foreach my $file (@files) {
        open(my $fh, '<', $file) or next;
        while (my $line = <$fh>) {
            chomp($line);
            $plugins{$file} = eval "\$line" if $line =~ /^Plugin/;
        }
        close($fh);
    }
}

sub run_plugins {
    foreach my $plugin (values %plugins) {
        eval $plugin;
    }
}

